const offset = Math.max(0, Number(msg.history_offset) || 0);
const limitRaw = Number(msg.history_limit) || 5;
const limit = Math.min(50, Math.max(1, limitRaw));

msg.topic = `
SELECT *
FROM v_hydro_recent_activity
ORDER BY activity_time DESC
LIMIT ${limit}
OFFSET ${offset};
`;

return msg;

// ─────────────────────────────────────────────────────────────
// Format Recent Activity
//
// Purpose:
//   Format records from v_hydro_recent_activity for the Home
//   Assistant Hydro-History browser.
//
// Measurement Model:
//   - Maintenance events contain before/after A0 and A1 voltage snapshots.
//   - EC_REFERENCE events contain one synchronized A0/A1 snapshot.
//   - meter_value is the handheld EC reference measurement.
//   - Analog probe voltages are not labeled as EC or TDS.
//
// Display Strategy:
//   - Use filtered voltages for concise operator-facing cards.
//   - Preserve raw voltages in the returned record object.
//   - Reject NULL and blank values before numeric conversion.
//
// Revision History:
//
// GAL 2026-07-21
// - Removed legacy tds_voltage references.
// - Added A0/A1 filtered before-and-after cycle display.
// - Added A0/A1 filtered EC-reference display.
// - Preserved all view columns in the returned record object.
//
// GAL 2026-07-04
// - Added meter_value and meter_units support.
//
// GAL 2026-07-01
// - Added operator notes and water temperature.
// ─────────────────────────────────────────────────────────────

const rows =
    Array.isArray(msg.payload)
        ? msg.payload
        : [];

/**
 * Format a numeric value.
 *
 * Important:
 * Number(null) becomes zero in JavaScript, so NULL and blank
 * values must be rejected before conversion.
 */
function fmtNum(value, decimals) {
    if (
        value === null ||
        value === undefined ||
        value === ""
    ) {
        return null;
    }

    const numberValue =
        Number(value);

    return Number.isFinite(numberValue)
        ? numberValue.toFixed(decimals)
        : null;
}

/**
 * Format the activity timestamp for dashboard display.
 */
function fmtDate(value) {
    if (!value) {
        return "";
    }

    const date =
        new Date(value);

    if (Number.isNaN(date.getTime())) {
        return String(value);
    }

    return date.toLocaleString(
        "en-US",
        {
            weekday: "short",
            month: "short",
            day: "numeric",
            hour: "numeric",
            minute: "2-digit",
            hour12: true
        }
    );
}

/**
 * Add a single voltage value when it is available.
 */
function addVoltageValue(
    details,
    label,
    value,
    separator
) {
    const formatted =
        fmtNum(value, 3);

    if (formatted !== null) {
        details.push(
            `${label}${separator}${formatted} V`
        );
    }
}

/**
 * Add a before-and-after voltage summary.
 */
function addVoltageChange(
    details,
    label,
    beforeValue,
    afterValue,
    separator
) {
    const before =
        fmtNum(beforeValue, 3);

    const after =
        fmtNum(afterValue, 3);

    if (
        before !== null &&
        after !== null
    ) {
        details.push(
            `${label}${separator}${before} → ${after} V`
        );
    } else if (before !== null) {
        details.push(
            `${label} Before${separator}${before} V`
        );
    } else if (after !== null) {
        details.push(
            `${label} After${separator}${after} V`
        );
    }
}

/**
 * Build event-specific card details.
 *
 * NOTE and EC_REFERENCE records must not inherit generic
 * fill or dose fields.
 */
function buildDetails(
    record,
    withColons = false
) {
    const type =
        String(
            record.event_type || ""
        ).toUpperCase();

    const details = [];

    const separator =
        withColons
            ? ": "
            : " ";

    const fill =
        fmtNum(record.fill_gallons, 2);

    const doseA =
        fmtNum(record.dose_a_ml, 0);

    const doseB =
        fmtNum(record.dose_b_ml, 0);

    const tank =
        fmtNum(record.tank_gallons, 1);

    const temp =
        fmtNum(record.water_temp_f, 1);

    if (type === "FILL") {
        if (fill !== null) {
            details.push(
                `Fill${separator}${fill} gal`
            );
        }

        if (doseA !== null) {
            details.push(
                `A${separator}${doseA} mL`
            );
        }

        if (doseB !== null) {
            details.push(
                `B${separator}${doseB} mL`
            );
        }

        addVoltageChange(
            details,
            "A0 Filtered",
            record.a0_filtered_v_before,
            record.a0_filtered_v_after,
            separator
        );

        addVoltageChange(
            details,
            "A1 Filtered",
            record.a1_filtered_v_before,
            record.a1_filtered_v_after,
            separator
        );

        if (tank !== null) {
            details.push(
                `Start${separator}${tank} gal`
            );
        }

        return details;
    }

    if (type === "EC_REFERENCE") {
        const meter =
            fmtNum(record.meter_value, 2);

        const units =
            record.meter_units || "EC";

        if (meter !== null) {
            details.push(
                `Meter${separator}${meter} ${units}`
            );
        }

        addVoltageValue(
            details,
            "A0 Filtered",
            record.a0_filtered_v,
            separator
        );

        addVoltageValue(
            details,
            "A1 Filtered",
            record.a1_filtered_v,
            separator
        );

        if (tank !== null) {
            details.push(
                `Tank${separator}${tank} gal`
            );
        }

        if (temp !== null) {
            details.push(
                `Temp${separator}${temp} °F`
            );
        }

        return details;
    }

    if (type === "DOSE") {
        if (doseA !== null) {
            details.push(
                `A${separator}${doseA} mL`
            );
        }

        if (doseB !== null) {
            details.push(
                `B${separator}${doseB} mL`
            );
        }

        addVoltageChange(
            details,
            "A0 Filtered",
            record.a0_filtered_v_before,
            record.a0_filtered_v_after,
            separator
        );

        addVoltageChange(
            details,
            "A1 Filtered",
            record.a1_filtered_v_before,
            record.a1_filtered_v_after,
            separator
        );

        if (tank !== null) {
            details.push(
                `Tank${separator}${tank} gal`
            );
        }

        return details;
    }

    if (type === "NOTE") {
        // NOTE records display their note text below the header.
        return details;
    }

    // Fallback for any additional maintenance event types.
    if (fill !== null) {
        details.push(
            `Fill${separator}${fill} gal`
        );
    }

    if (doseA !== null) {
        details.push(
            `A${separator}${doseA} mL`
        );
    }

    if (doseB !== null) {
        details.push(
            `B${separator}${doseB} mL`
        );
    }

    addVoltageChange(
        details,
        "A0 Filtered",
        record.a0_filtered_v_before,
        record.a0_filtered_v_after,
        separator
    );

    addVoltageChange(
        details,
        "A1 Filtered",
        record.a1_filtered_v_before,
        record.a1_filtered_v_after,
        separator
    );

    if (tank !== null) {
        details.push(
            `Start${separator}${tank} gal`
        );
    }

    if (temp !== null) {
        details.push(
            `Temp${separator}${temp} °F`
        );
    }

    return details;
}

const records =
    rows.map(record => {
        const title =
            `#${record.source_id} — ` +
            `${record.event_type || "EVENT"}`;

        const details =
            buildDetails(record, false);

        let label =
            fmtDate(record.activity_time);

        if (record.source) {
            label +=
                ` · ${record.source}`;
        }

        if (details.length > 0) {
            label +=
                `\n${details.join(" · ")}`;
        }

        if (record.note) {
            label +=
                `\n${String(record.note).slice(0, 240)}`;
        }

        if (record.operator_note) {
            label +=
                `\nOperator Note: ` +
                `${String(record.operator_note).slice(0, 240)}`;
        }

        return {
            ...record,
            card_title: title,
            card_label: label,
            select_id:
                `${record.activity_source}:` +
                `${record.source_id}`
        };
    });

const lines =
    records.map(record => {
        const details =
            buildDetails(record, true);

        let line =
            `### ${record.card_title}\n`;

        line +=
            `**${fmtDate(record.activity_time)}**`;

        if (record.source) {
            line +=
                ` · ${record.source}`;
        }

        line += "\n\n";

        if (details.length > 0) {
            line +=
                details.join(" · ") +
                "\n\n";
        }

        if (record.note) {
            line +=
                `${String(record.note).slice(0, 240)}\n`;
        }

        if (record.operator_note) {
            line +=
                `\n**Operator Note:** ` +
                `${String(record.operator_note).slice(0, 240)}\n`;
        }

        return line;
    });

msg.payload =
    JSON.stringify({
        state: "ok",
        activity_text:
            lines.join("\n---\n"),
        records: records,
        updated_at:
            new Date().toISOString()
    });

return msg;

// ─────────────────────────────────────────────────────────────
// Build EC Reference SELECT
//
// Purpose:
//   Retrieve recent handheld EC reference readings with the
//   synchronized A0/A1 raw and filtered voltage snapshots.
//
// GAL 2026-07-22
// - Replaced legacy probe_voltage selection.
// - Added A0/A1 raw and filtered voltage fields.
// ─────────────────────────────────────────────────────────────

msg.topic = `
SELECT
    id,
    captured_at,

    meter_value,
    meter_units,

    a0_raw_v,
    a0_filtered_v,
    a1_raw_v,
    a1_filtered_v,

    tank_gallons,
    water_temp_f,

    rain_since_last_reference_in,
    estimated_rain_added_gal,

    note,
    operator_note

FROM hydro_tds_reference_reading

ORDER BY captured_at DESC

LIMIT 20;
`;

return msg;

// ─────────────────────────────────────────────────────────────
// Format EC Reference History
//
// Purpose:
//   Format handheld EC reference records for the dedicated
//   Home Assistant EC Reference History display.
//
// Measurement Model:
//   - meter_value is the handheld reference measurement.
//   - A0 is the KEYESTUDIO production/control channel.
//   - A1 is the DFRobot validation/reference channel.
//   - Raw and filtered values are voltages, not EC or TDS.
//
// Display Strategy:
//   - Show filtered A0 and A1 voltages in the concise history.
//   - Keep raw A0/A1 values available in the database.
//   - Preserve NULL database values as a dash.
//
// Revision History:
//
// GAL 2026-07-21
// - Replaced legacy probe_voltage display.
// - Added A0 and A1 filtered voltage display.
// - Preserved existing meter, tank, temperature, rain, and note data.
// ─────────────────────────────────────────────────────────────

const rows =
    Array.isArray(msg.payload)
        ? msg.payload
        : [];

/**
 * Format a numeric value for dashboard display.
 *
 * NULL and blank values must remain unavailable rather than
 * being converted to zero.
 */
function fmt(value, decimals) {
    if (
        value === null ||
        value === undefined ||
        value === ""
    ) {
        return "-";
    }

    const numberValue =
        Number(value);

    if (!Number.isFinite(numberValue)) {
        return "-";
    }

    return numberValue.toFixed(decimals);
}

/**
 * Format the database timestamp for dashboard display.
 */
function fmtDate(value) {
    const date =
        new Date(value);

    if (Number.isNaN(date.getTime())) {
        return String(value || "");
    }

    return date.toLocaleString(
        "en-US",
        {
            weekday: "short",
            month: "short",
            day: "numeric",
            hour: "numeric",
            minute: "2-digit",
            hour12: true
        }
    );
}

const markdown =
    rows.map(record => {
        let text =
            `### ${fmtDate(record.captured_at)}\n`;

        text +=
            `**Meter:** ` +
            `${fmt(record.meter_value, 2)} ` +
            `${record.meter_units || ""}`;

        text +=
            `  •  **A0 Filtered:** ` +
            `${fmt(record.a0_filtered_v, 3)} V`;

        text +=
            `  •  **A1 Filtered:** ` +
            `${fmt(record.a1_filtered_v, 3)} V`;

        text +=
            `  •  **Tank:** ` +
            `${fmt(record.tank_gallons, 1)} gal`;

        text +=
            `  •  **Temp:** ` +
            `${fmt(record.water_temp_f, 1)} °F\n\n`;

        text +=
            `Rain Since: ` +
            `${fmt(record.rain_since_last_reference_in, 3)} in`;

        text +=
            `  •  Rain Added: ` +
            `${fmt(record.estimated_rain_added_gal, 3)} gal\n\n`;

        if (record.note) {
            text +=
                `${String(record.note)}\n`;
        }

        if (record.operator_note) {
            text +=
                `\n**Operator Note:** ` +
                `${String(record.operator_note)}\n`;
        }

        return text;
    }).join("\n---\n");

msg.payload =
    JSON.stringify({
        state: "ok",
        ec_reference_text: markdown,
        updated_at:
            new Date().toISOString()
    });

return msg;
